import { BrowserRouter as Router, Switch, Route, Link } from "react-router-dom";
import BlockExplorerPage from "./BlockExplorerPage";
import AccountsPage from "./AccountsPage";
import "./styles.css";

function App() {
  return (
    <Router>
      <nav className="navbar">
        <Link to="/" className="nav-item button">Block Explorer</Link>
        <Link to="/accounts" className="nav-item button">Accounts</Link>
      </nav>

      <Switch>
        <Route exact path="/" component={BlockExplorerPage} />
        <Route path="/accounts" component={AccountsPage} />
      </Switch>
    </Router>
  );
}

export default App;
